INSERT INTO messages (id, created_at, updated_at, conversation_id, sender_user_id, message_type, body, read_at) VALUES
                                                                                                                    (1,  '2026-02-16 09:01:00', '2026-02-16 09:01:00', 1, 2,  'TEXT', 'Hi! Interested in the Smart Speaker Launch. Can you share your audience geo?', '2026-02-16 09:02:10'),
                                                                                                                    (2,  '2026-02-16 09:03:00', '2026-02-16 09:03:00', 1, 8,  'TEXT', 'Sure. Main countries: KZ, US, GB. I can tailor content for US/GB.', '2026-02-16 09:04:00'),
                                                                                                                    (3,  '2026-02-16 09:06:00', '2026-02-16 09:06:00', 1, 2,  'TEXT', 'Great. Please propose 2 integrations and a short unboxing clip.', NULL),
                                                                                                                    (4,  '2026-02-16 10:01:00', '2026-02-16 10:01:00', 2, 2,  'TEXT', 'We need a gaming headset review + shorts. Are you comfortable with a scripted hook?', '2026-02-16 10:02:00'),
                                                                                                                    (5,  '2026-02-16 10:05:00', '2026-02-16 10:05:00', 2, 9,  'TEXT', 'Yes. I can do a 30s hook and a longer review.', NULL),
                                                                                                                    (6,  '2026-02-16 11:02:00', '2026-02-16 11:02:00', 3, 4,  'TEXT', 'For Weekend City Breaks, can you do itinerary format + booking CTA?', '2026-02-16 11:03:00'),
                                                                                                                    (7,  '2026-02-16 11:06:00', '2026-02-16 11:06:00', 3, 13, 'TEXT', 'Yes. I can do 2 cities and include tracking link in description.', NULL),
                                                                                                                    (8,  '2026-02-16 12:02:00', '2026-02-16 12:02:00', 4, 6,  'TEXT', 'Budgeting Basics: we want clear onboarding steps and feature highlights.', '2026-02-16 12:03:00'),
                                                                                                                    (9,  '2026-02-16 12:06:00', '2026-02-16 12:06:00', 4, 15, 'TEXT', 'Got it. I will do a walkthrough + 3 tips, no financial promises.', NULL),
                                                                                                                    (10, '2026-02-16 13:01:00', '2026-02-16 13:01:00', 5, 1,  'TEXT', 'Please keep communications inside the platform for audit trail.', '2026-02-16 13:02:00'),
                                                                                                                    (11, '2026-02-16 13:04:00', '2026-02-16 13:04:00', 5, 2,  'TEXT', 'Understood. We will use the platform chat only.', NULL),
                                                                                                                    (12, '2026-02-16 14:01:00', '2026-02-16 14:01:00', 6, 7,  'TEXT', 'Skincare Routine: do you prefer reels or a longer YouTube video?', '2026-02-16 14:02:00'),
                                                                                                                    (13, '2026-02-16 14:06:00', '2026-02-16 14:06:00', 6, 10, 'TEXT', 'Reels + a short routine checklist in caption works best for my audience.', NULL);
