INSERT INTO chat_widget_messages (id, created_at, updated_at, session_id, sender, text, intent, metadata) VALUES
                                                                                                              (1,  '2026-02-20 09:00:10', '2026-02-20 09:00:10', 1,  'USER', 'How do I create an offer?', 'help.create_offer', '{"channel":"widget","lang":"en","confidence":0.91}'::jsonb),
                                                                                                              (2,  '2026-02-20 09:00:12', '2026-02-20 09:00:12', 1,  'BOT',  'Go to Offers → Create. Fill title, description, category, budget, and target ages.', 'help.create_offer', '{"channel":"widget","lang":"en","confidence":0.91,"actions":[{"type":"navigate","to":"/offers/new"}]}'::jsonb),
                                                                                                              (3,  '2026-02-20 09:03:00', '2026-02-20 09:03:00', 1,  'USER', 'Can I target multiple countries?', 'help.targeting', '{"channel":"widget","lang":"en","confidence":0.88}'::jsonb),
                                                                                                              (4,  '2026-02-20 09:03:02', '2026-02-20 09:03:02', 1,  'BOT',  'Yes. Add countries in the targeting section of the offer.', 'help.targeting', '{"channel":"widget","lang":"en","confidence":0.88}'::jsonb),
                                                                                                              (5,  '2026-02-20 10:10:10', '2026-02-20 10:10:10', 2,  'USER', 'Где посмотреть мои предложения?', 'help.my_offers', '{"channel":"widget","lang":"ru","confidence":0.86}'::jsonb),
                                                                                                              (6,  '2026-02-20 10:10:12', '2026-02-20 10:10:12', 2,  'BOT',  'Откройте раздел Offers в личном кабинете.', 'help.my_offers', '{"channel":"widget","lang":"ru","confidence":0.86,"actions":[{"type":"navigate","to":"/offers"}]}'::jsonb),
                                                                                                              (7,  '2026-02-21 11:30:10', '2026-02-21 11:30:10', 3,  'USER', 'What does risk label mean?', 'help.risk_label', '{"channel":"widget","lang":"en","confidence":0.84}'::jsonb),
                                                                                                              (8,  '2026-02-21 11:30:12', '2026-02-21 11:30:12', 3,  'BOT',  'It summarizes content safety checks (LOW/MEDIUM/HIGH) and moderation status.', 'help.risk_label', '{"channel":"widget","lang":"en","confidence":0.84}'::jsonb),
                                                                                                              (9,  '2026-02-21 16:00:10', '2026-02-21 16:00:10', 4,  'USER', 'Can I contact the company directly?', 'help.messaging', '{"channel":"widget","lang":"en","confidence":0.79}'::jsonb),
                                                                                                              (10, '2026-02-21 16:00:12', '2026-02-21 16:00:12', 4,  'BOT',  'Use the platform chat inside the offer conversation to keep everything tracked.', 'help.messaging', '{"channel":"widget","lang":"en","confidence":0.79}'::jsonb),
                                                                                                              (11, '2026-02-22 09:15:10', '2026-02-22 09:15:10', 5,  'USER', 'Как поменять индустрию компании?', 'help.company_industry', '{"channel":"widget","lang":"ru","confidence":0.87}'::jsonb),
                                                                                                              (12, '2026-02-22 09:15:12', '2026-02-22 09:15:12', 5,  'BOT',  'Откройте профиль компании и выберите новую индустрию, затем сохраните изменения.', 'help.company_industry', '{"channel":"widget","lang":"ru","confidence":0.87,"actions":[{"type":"navigate","to":"/company/profile"}]}'::jsonb),
